<section class="admin-page-head"><div><p class="eyebrow">FINANCIAR</p><h1>RO e-Factura</h1><p>Transmiterea rămâne oprită până la autorizarea OAuth ANAF; nicio factură nu este marcată acceptată fără răspuns ANAF.</p></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="admin-two-columns"><section class="admin-panel"><h2>Conexiuni ANAF</h2><?php foreach($connections as $item): ?><div class="connector-row"><div><strong><?= e($item['legal_name']) ?></strong><small><?= e($item['environment']) ?> · <?= e($item['last_error']?:'Fără eroare raportată') ?></small></div><span class="status-pill <?= $item['status']==='connected'?'success':'' ?>"><?= e($item['status']) ?></span></div><?php endforeach; ?><?php if(!$connections): ?><p>Nicio conexiune configurată.</p><?php endif; ?></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/facturare/efactura')) ?>"><?= csrf_field() ?><h2>Pregătește conexiunea</h2><label>Mediu<select name="environment"><option value="test">Test</option><option value="production">Producție</option></select></label><label>Client ID ANAF<input name="client_id"></label><label>Redirect URI<input readonly value="<?= e(absolute_url('/admin/facturare/efactura/callback')) ?>"></label><button class="admin-button" type="submit">Salvează configurarea</button></form></aside></div><section class="admin-panel"><h2>Transmiteri recente</h2><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Factură</th><th>Status</th><th>Upload ID</th><th>Încercări</th><th>Actualizat</th></tr></thead><tbody><?php foreach($submissions as $item): ?><tr><td><?= e($item['invoice_number']) ?></td><td><?= e($item['status']) ?></td><td><?= e($item['upload_id']?:'—') ?></td><td><?= (int)$item['attempts'] ?></td><td><?= date('d.m.Y H:i',strtotime($item['updated_at'])) ?></td></tr><?php endforeach; ?></tbody></table></div></section>
